- The overall passing rate is the average of math and reading passing rates.;
- The average budget per student is calculated by dividing the total budget by the total number of students.;
- The query ranks schools primarily by their overall passing rate and secondarily by their average budget per student.;

sql:
SELECT COUNT(budget_id) 
FROM budget_details 
WHERE funding_source = 2 AND num_students_funded > 2949;

SELECT school_id, SUM(total_budget) AS total_budget
FROM budget_details
GROUP BY school_id;

SELECT school_name, total_budget
FROM schools
WHERE total_budget > (SELECT AVG(total_budget) FROM schools);

SELECT type_name
FROM school_types
WHERE type_id = 1;

